query_text:
db.network_traffic_logs.aggregate([
    { 
        $group: { 
            _id: "$timestamp", 
            total_traffic: { $sum: "$data_transferred_mb" }
        } 
    },
    { $sort: { total_traffic: -1 } },
    { $limit: 5 }
]);

db.api_requests.aggregate([
    { $match: { status_code: { $gte: 500 } } },
    { $group: { _id: "$endpoint", error_count: { $sum: 1 } } },
    { $sort: { error_count: -1 } },
    { $limit: 5 }
]);

db.logs.aggregate([
    { $match: { log_level: "ERROR" } },
    { $group: { _id: "$message", count: { $sum: 1 } } },
    { $sort: { count: -1 } },
    { $limit: 5 }
]);

db.sensors.aggregate([
  { $group: { _id: "$status", count: { $sum: 1 } } }
]);

db.sensors.aggregate([
  { $group: { _id: "$location.zone", sensorCount: { $sum: 1 } } },
  { $sort: { sensorCount: -1 } }
]);

db.sensor_data.aggregate([
  { $match: { "data.energy_usage.consumption_kwh": { $exists: true } } },
  { $group: { _id: { hour: { $hour: "$timestamp" } },
              avgConsumption: { $avg: "$data.energy_usage.consumption_kwh" } } },
  { $sort: { "_id.hour": 1 } }
]);

db.alerts.aggregate([
  { $match: { resolved: false } },
  { $group: { _id: "$sensor_id", unresolvedCount: { $sum: 1 } } },
  { $sort: { unresolvedCount: -1 } }
]);

db.sensor_data.aggregate([
  { $lookup: { from: "sensors", localField: "sensor_id", foreignField: "sensor_id", as: "sensor" } },
  { $unwind: "$sensor" },
  { $group: { _id: "$sensor.location.zone", avgAQI: { $avg: "$data.air_quality.AQI" } } },
  { $sort: { avgAQI: -1 } }
]);

db.shipments.aggregate([
    { "$group": { "_id": "$currentStatus.status", "count": { "$sum": 1 } } }
])

db.genomes.aggregate([
  { "$group": { "_id": "$genome_metadata.instrument_used", "count": { "$sum": 1 } } },
  { "$sort": { "count": -1 } }
])

db.patients.aggregate([
  { "$group": { "_id": "$ethnicity", "count": { "$sum": 1 } } }
])

db.users.aggregate([
  { "$group": { "_id": "$role", "count": { "$sum": 1 } } }
])

db.analysis_results.aggregate([
  { "$group": { "_id": "$researcher_id", "count": { "$sum": 1 } } },
  { "$sort": { "count": -1 } },
  { "$limit": 10 }
])

db.comments.aggregate([
    { "$unwind": "$hashtags" },
    { "$group": { "_id": "$hashtags", "avg_sentiment": { "$avg": "$sentiment_score" } } },
    { "$sort": { "avg_sentiment": -1 } }
])

db.comments.aggregate([
    { "$group": { "_id": "$platform", "avg_sentiment": { "$avg": "$sentiment_score" } } }
])

db.social_posts.aggregate([
    { "$group": { "_id": "$user.user_id", "post_count": { "$sum": 1 } } },
    { "$sort": { "post_count": -1 } },
    { "$limit": 10 }
])

db.comments.aggregate([
    { "$group": { "_id": "$platform", "total_comments": { "$sum": 1 } } },
    { "$sort": { "total_comments": -1 } }
])

db.comments.aggregate([
    { "$match": { "created_at_platform": { "$gte": ISODate("YYYY-MM-DD"), "$lte": ISODate("YYYY-MM-DD") } } },
    { "$group": { "_id": "$sentiment_label", "count": { "$sum": 1 } } }
])

db.transactions.aggregate([
  { $unwind: "$items_purchased" },
  {
    $group: {
      _id: "$transaction_id",
      products: { $push: "$items_purchased.product_name" }
    }
  },
  { $unwind: "$products" },
  {
    $group: {
      _id: "$products",
      frequently_bought_with: { $addToSet: "$products" }
    }
  }
])

db.transactions.aggregate([
  {
    $group: {
      _id: "$store_id",
      total_sales: { $sum: "$total_amount" }
    }
  },
  { $sort: { total_sales: -1 } },
  { $facet: {
      top_performing: [ { $limit: 5 } ],
      low_performing: [ { $sort: { total_sales: 1 } }, { $limit: 5 } ]
    }
  }
])

db.transactions.aggregate([
  {
    $group: {
      _id: "$channel",
      total_sales: { $sum: "$total_amount" },
      transaction_count: { $sum: 1 }
    }
  },
  { $sort: { total_sales: -1 } }
])

db.transactions.aggregate([
  {
    $group: {
      _id: null,
      total_revenue: { $sum: "$total_amount" },
      total_orders: { $sum: 1 }
    }
  },
  {
    $project: {
      _id: 0,
      avg_order_value: { $divide: ["$total_revenue", "$total_orders"] }
    }
  }
])

db.transactions.aggregate([
  {
    $project: {
      hour: { $hour: "$transaction_date" },
      total_amount: 1
    }
  },
  {
    $group: {
      _id: "$hour",
      total_sales: { $sum: "$total_amount" }
    }
  },
  { $sort: { _id: 1 } }
])

db.transactions.aggregate([
  {
    $lookup: {
      from: "behavior_profiles",
      localField: "customer_id",
      foreignField: "customer_id",
      as: "profile"
    }
  },
  { $unwind: "$profile" },
  {
    $match: {
      "merchant.location.address": { $nin: "$profile.geographical_activity_zones" }
    }
  }
])

db.accounts.aggregate([
  { $match: { balance: { $lt: 100 } } },  
  {
    $lookup: {
      from: "transactions",
      localField: "account_id",
      foreignField: "account_id",
      as: "recent_transactions"
    }
  },
  { $unwind: "$recent_transactions" },
  { 
    $match: { 
      "recent_transactions.transaction_date": { 
        $gte: new Date(new Date().setDate(new Date().getDate() - 7))  
      } 
    }
  },
  { 
    $group: {
      _id: "$account_id",
      total_spent: { $sum: "$recent_transactions.amount" },
      balance: { $first: "$balance" }
    }
  },
  { 
    $match: { 
      $expr: { 
        $gt: ["$total_spent", { $multiply: ["$balance", 2] }] }  
    } 
  }
])

db.transactions.aggregate([
  { $match: { "fraud_flag": true } },
  { $group: { _id: null, avg_fraud_amount: { $avg: "$amount" } } }
])

db.transactions.aggregate([
  { $match: { "fraud_flag": true } },
  {
    $project: {
      hour: { $hour: "$transaction_date" }
    }
  },
  {
    $group: {
      _id: "$hour",
      fraud_count: { $sum: 1 }
    }
  },
  { $sort: { "_id": 1 } }
])

db.transactions.aggregate([
  {
    $match: {
      "transactions.date": {
        $gte: new Date("2016-12-01T00:00:00.000Z"),
        $lt: new Date("2017-01-01T00:00:00.000Z")
      }
    }
  },
  {
    $unwind: "$transactions"
  },
  {
    $match: {
      "transactions.date": {
        $gte: new Date("2016-12-01T00:00:00.000Z"),
        $lt: new Date("2017-01-01T00:00:00.000Z")
      }
    }
  },
  {
    $group: {
      _id: null,
      totalAmount: {
        $sum: "$transactions.amount"
      }
    }
  },
  {
    $project: {
      _id: 0,
      totalAmount: 1
    }
  }
])

db.listingsAndReviews.aggregate([
  {
    $match: {
      amenities: "Swimming pool",
      "availability.availability_30": { $gt: 0 }
    }
  },
  {
    $project: {
      listing_url: 1,
      name: 1,
      summary: 1,
      description: 1,
      price: 1,
      "host.host_name": 1,
      "address.street": 1,
      "address.suburb": 1,
      "address.country": 1
    }
  }
])

db.listingsAndReviews.aggregate([
  {
    $match: {
      property_type: "Apartment"
    }
  },
  {
    $group: {
      _id: null,
      avg_cleanliness: { $avg: "$review_scores.review_scores_cleanliness" },
      avg_communication: { $avg: "$review_scores.review_scores_communication" }
    }
  },
  {
    $project: {
      _id: 0,
      avg_cleanliness: 1,
      avg_communication: 1
    }
  }
])

db.listingsAndReviews.aggregate([
  {
    $match: {
      "host.host_response_rate": { $gte: 50, $lte: 100 }
    }
  },
  {
    $project: {
      _id: 0,
      host: { host_response_rate: 1 },
      review_scores: { review_scores_rating: 1 }
    }
  },
  {
    $limit: 20
  }
])

db.listingsAndReviews.aggregate([
  {
    $match: {
      room_type: "Private room",
      amenities: "Pool"
    }
  },
  {
    $project: {
      listing_url: 1,
      name: 1,
      amenities: 1,
      room_type: 1
    }
  },
  {
    $limit: 5
  }
])

db.sales.aggregate([
  {
    $match: {
      purchaseMethod: "Online",
      saleDate: {
        $gte: new Date("2017-10-01T00:00:00.000Z"),
        $lte: new Date("2017-12-31T23:59:59.999Z")
      }
    }
  },
  {
    $group: {
      _id: null,
      averageSatisfaction: { $avg: "$customer.satisfaction" }
    }
  },
  {
    $project: {
      _id: 0,
      averageSatisfaction: 1
    }
  }
])

db.sales.aggregate([
  { $match: {
    'items.tags': 'school'
  }},
  { $group: {
    _id: '$storeLocation',
    averageSatisfaction: { $avg: '$customer.satisfaction' }
  }},
  { $sort: { averageSatisfaction: -1 }},
  { $limit: 3 },
  { $project: { _id: 0, storeLocation: '$_id', averageSatisfaction: 1 }}
])

db.sales.aggregate([
  {
    $match: {
      storeLocation: 'Denver',
      saleDate: {
        $gte: new Date('2017-01-01T00:00:00.000Z'),
        $lt: new Date('2018-01-01T00:00:00.000Z')
      }
    }
  },
  {
    $group: {
      _id: null,
      averageSatisfaction: { $avg: "$customer.satisfaction" }
    }
  },
  {
    $project: {
      _id: 0,
      averageSatisfaction: 1
    }
  }
])

db.sales.aggregate([
  { $match: { storeLocation: 'Denver' } },
  { $group: { _id: null, averageSatisfaction: { $avg: '$customer.satisfaction' } } },
  { $project: { _id: 0, averageSatisfaction: 1 } }
])

db.planets.aggregate([
  {
    $match: {
      mainAtmosphere: {
        $in: ['N']
      }
    }
  },
  {
    $project: {
      _id: 0,
      name: 1,
      mainAtmosphere: 1
    }
  }
])

db.planets.aggregate([
  {
    $match: {
      "surfaceTemperatureC.min": { $lt: -80 }
    }
  },
  {
    $project: {
      _id: 0,
      name: 1,
      "surfaceTemperatureC.min": 1
    }
  }
])

db.data.aggregate([
  {
    $match: {
      ts: {
        $gte: new Date('1984-03-01T00:00:00.000Z'),
        $lt: new Date('1984-04-01T00:00:00.000Z')
      },
      elevation: { $gt: 1000 }
    }
  },
  {
    $group: {
      _id: null,
      averageTemperature: { $avg: "$airTemperature.value" }
    }
  },
  {
    $project: {
      _id: 0,
      averageTemperature: 1
    }
  }
])

db.data.aggregate([
  {
    $match: {
      ts: {
        $gte: new Date('1984-03-01T00:00:00Z'),
        $lt: new Date('1984-04-01T00:00:00Z')
      }
    }
  },
  {
    $group: {
      _id: '$qualityControlProcess',
      qualityControlProcess: { $first: '$qualityControlProcess' }
    }
  },
  {
    $project: {
      _id: 0,
      qualityControlProcess: 1
    }
  }
])

db.data.aggregate([
  { $match: { type: 'FM-13' } },
  { $group: { _id: '$dataSource' } },
  { $project: { _id: 0, dataSource: '$_id' } }
])

db.restaurants.aggregate([
  { $match: { "address.zipcode": "10034" } },
  { $unwind: "$grades" },
  { $group: { _id: null, averageScore: { $avg: "$grades.score" } } },
  { $project: { _id: 0, averageScore: 1 } }
])

db.movies.aggregate([
    {
        $match: {
            directors: "Ridley Scott",
            cast: "Russell Crowe"
        }
    },
    {
        $project: {
            _id: 0,
            title: 1
        }
    },
    {
        $limit: 3
    }
])

db.movies.aggregate([
  {
    $match: {
      year: 2015,
      'awards.nominations': { $gt: 0 }
    }
  },
  {
    $project: {
      _id: 0,
      title: 1,
      awards: 1
    }
  },
  {
    $limit: 5
  }
])

db.theaters.aggregate([
  {
    $match: {
      "location.address.city": "Madison",
      "location.address.state": "WI"
    }
  },
  {
    $project: {
      _id: 0,
      theaterId: 1,
      "location.geo.coordinates": 1,
      "location.address.city": 1,
      "location.address.state": 1
    }
  },
  {
    $limit: 5
  }
])

db.movies.aggregate([
  {
    $match: {
      year: 2015
    }
  },
  {
    $sort: {
      num_mflix_comments: -1
    }
  },
  {
    $limit: 10
  },
  {
    $project: {
      _id: 0,
      genres: 1,
      runtime: 1
    }
  }
])

db.shipwrecks.aggregate([
  {
    $geoNear: {
      near: { type: 'Point', coordinates: [-86.7, 45.5] },
      distanceField: 'dist.calculated',
      maxDistance: 5000,
      spherical: true
    }
  },
  {
    $match: {
      history: { $regex: /reported\s(199[0-9]|2000)/ }
    }
  },
  {
    $project: {
      _id: 0,
      history: 1
    }
  }
])

db.shipwrecks.aggregate([
  {
    $match: {
      chart: { $eq: 'US,US,reprt,L-589/05' },
      watlev: { $eq: 'covers and uncovers' }
    }
  },
  {
    $project: {
      _id: 0,
      coordinates: 1,
      feature_type: 1
    }
  }
])
